#include <bits/stdc++.h>
using namespace std;
int main(){
int n;
string str;
cin >> n >> str;
stringstream ss(str);
string word, reversed_string;
while(ss >> word){
string reversed_word;
for(int i = word.size() - 1; i >= 0; --i) reversed_word += word[i];
reversed_string += reversed_word + ' ';
}
reversed_string.pop_back();
bool is_palindrome = true;
int left = 0, right = reversed_string.size() - 1;
while(left < right){
if(reversed_string[left++] != reversed_string[right--]){
is_palindrome = false;
break;
}
}
cout << boolalpha << is_palindrome << endl;
}
